UPDATE ielts_daily_plan_items
SET record_id = #{recordId,jdbcType=OTHER}
WHERE plan_id = #{planId,jdbcType=OTHER}
  AND content_type = #{contentType}
  AND content_id = #{contentId,jdbcType=OTHER}
  AND record_id IS NULL

UPDATE ielts_daily_plan_items
SET status = 'COMPLETED',
    completed_at = #{completedAt}
WHERE plan_id = #{planId,jdbcType=OTHER}
  AND record_id = #{recordId,jdbcType=OTHER}
  AND status = 'PENDING'

UPDATE ielts_daily_plan_items
SET status = 'COMPLETED',
    record_id = COALESCE(record_id, #{recordId,jdbcType=OTHER}),
    completed_at = #{completedAt}
WHERE plan_id = #{planId,jdbcType=OTHER}
  AND content_type = #{contentType}
  AND content_id = #{contentId,jdbcType=OTHER}
  AND status = 'PENDING'
